```typescript
class PriorityQueue<T> {
    private heap: T[];
    private compare: (a: T, b: T) => number;

    constructor(compare: (a: T, b: T) => number) {
        this.heap = [];
        this.compare = compare;
    }

    push(item: T): void {
        this.heap.push(item);
        this.siftUp(this.heap.length - 1);
    }

    pop(): T | undefined {
        if (this.heap.length === 0) return undefined;
        const top = this.heap[0];
        const last = this.heap.pop()!;
        if (this.heap.length > 0) {
            this.heap[0] = last;
            this.siftDown(0);
        }
        return top;
    }

    private siftUp(index: number): void {
        const item = this.heap[index];
        while (index > 0) {
            const parentIndex = (index - 1) >> 1;
            const parent = this.heap[parentIndex];
            if (this.compare(item, parent) <= 0) {
                this.heap[index] = parent;
                index = parentIndex;
            } else {
                break;
            }
        }
        this.heap[index] = item;
    }

    private siftDown(index: number): void {
        const halfLength = this.heap.length >> 1;
        const item = this.heap[index];
        while (index < halfLength) {
            let leftChildIndex = 2 * index + 1;
            let leftChild = this.heap[leftChildIndex];
            let rightChildIndex = leftChildIndex + 1;
            let rightChild = this.heap[rightChildIndex];
            let swapIndex = leftChildIndex;

            if (rightChildIndex < this.heap.length && this.compare(rightChild, leftChild) < 0) {
                swapIndex = rightChildIndex;
                leftChild = rightChild;
            }

            if (this.compare(item, leftChild) <= 0) {
                break;
            }

            this.heap[index] = leftChild;
            index = swapIndex;
        }
        this.heap[index] = item;
    }
}
```

